from pathlib import Path
import re

WIKI_DIR = Path\("09-AI总结/wiki"\)
exclude = {"index.md", "log.md", "hot.md", "overview.md", "health-report.md", "lint-report.md"}
# Strip .md from disk files for comparison
disk_files = {p.relative_to\(WIKI_DIR\).with_suffix\(""\) for p in WIKI_DIR.rglob\("*.md"\) if p.name not in exclude}

index_content = \(WIKI_DIR / "index.md"\).read_text\(encoding="utf-8"\)
wikilinks = set\(re.findall\(r"\\[\\[\([^\\]]+\)\\]\\]", index_content\)\)
index_links = {link.split\("|"\)[0] for link in wikilinks}

missing = disk_files - index_links
extra = index_links - disk_files

print\(f"Disk files \(w/o .md\): {len\(disk_files\)}"\)
print\(f"Index entries:        {len\(index_links\)}"\)

if missing:
    print\(f"\\n❌ In disk, NOT in index \({len\(missing\)}\):"\)
    for f in sorted\(missing\): print\(f"  - {f}"\)
else:
    print\("\\n✅ All disk files accounted for in index"\)

if extra:
    print\(f"\\n❌ In index, NOT on disk \({len\(extra\)}\):"\)
    for f in sorted\(extra\): print\(f"  - {f}"\)
else:
    print\("✅ All index entries exist on disk"\)
PYEOF)
